+}
+
+function fitExamColumn(col) {
+    const boxes = [...col.querySelectorAll('.q-box')];
+    boxes.forEach(box => fitQuestionBox(box));
+}
+
+function fitQuestionBox(box) {
+    const fitClasses = ['', 'fit-tight', 'fit-tighter', 'fit-micro'];
+
+    for (const cls of fitClasses) {
+        box.classList.remove('fit-tight', 'fit-tighter', 'fit-micro');
+        if (cls) box.classList.add(cls);
+
+        if (box.scrollHeight <= box.clientHeight + 1) {
+            return;
+        }
+    }
+
+    const choices = box.querySelector('.choices');
+    if (choices) {
+        choices.style.lineHeight = '1.2';
+        choices.style.marginTop = '1px';
+    }
+
+    const qnum = box.querySelector('.q-num');
+    if (qnum) {
+        qnum.style.marginBottom = '1px';
+    }
+}
+
+function buildSolHeader(q, i) {
+    return `
+        <div class="sol-head">
+            <div class="q-num">${i + 1}.
+                <span style="font-size:9pt;font-weight:normal;">
+                    ${wrapLatex(q.content || q.question || '')}
+                </span>
+            </div>
+        </div>
+    `;
+}
+
+function buildSolFragments(q) {
+    if (q.solution_steps?.length) {
+        return q.solution_steps.map((s, si) => `
+            <div class="sol-frag">
+                <div class="sol-step"><b>[${si + 1}단계]</b> ${wrapLatexPreserveBlocks(stripCite(s))}</div>
+            </div>
+        `);
+    }
+
+    if (q.solution) {
+        const raw = stripCite(q.solution);
+
+        const hasStructuredMath =
+            /\\begin\{(array|aligned|matrix|pmatrix|bmatrix|vmatrix|Vmatrix|cases)\}/.test(raw) ||
+            /\\multicolumn|\\cline|\\hline/.test(raw);
+
+        if (hasStructuredMath) {
+            return [
+                `<div class="sol-frag"><div class="sol-step">${wrapLatexPreserveBlocks(raw)}</div></div>`
+            ];
+        }
+
+        const lines = raw
+            .split(/\n+/)
+            .map(v => v.trim())
+            .filter(Boolean);
+
