+    const splitIndex = Math.ceil(bank.length / 2);
+    const orderedItems = [];
+
+    for (let i = 0; i < splitIndex; i++) {
+        orderedItems.push({ q: bank[i], qNum: i + 1 });
+        if (bank[splitIndex + i]) {
+            orderedItems.push({ q: bank[splitIndex + i], qNum: splitIndex + i + 1 });
+        }
+    }
+
+    orderedItems.forEach(({ q, qNum }) => {
+        const cell = document.createElement('div');
+        cell.className = 'ans-cell';
+        const rawAns = String(q.answer ?? '–');
+        const displayAns = (rawAns.includes('sqrt') || rawAns.includes('/') || rawAns.includes('^'))
+            ? wrapLatex(rawAns)
+            : rawAns;
+
+        cell.innerHTML = `<b style="font-size:10.5pt;min-width:35px;">${qNum}.</b>
+                          <span style="font-size:10.5pt;">${wrapLatex(displayAns)}</span>`;
+        grid.appendChild(cell);
+    });
+
+    p.body.appendChild(grid);
+    if (window.MathJax?.typesetPromise) MathJax.typesetPromise([p.body]);
+}
+
+function makePage(area, type) {
+    pageCount++;
+    const page = document.createElement('div');
+    page.className = 'page';
+
+    const header = document.createElement('div');
+    header.className = 'page-header';
+    header.innerHTML = `<span>${AppState.title}</span><span>- ${pageCount} -</span>`;
+    page.appendChild(header);
+
+    if (type === 'ans') {
+        const body = document.createElement('div');
+        body.style.flex = '1';
+        page.appendChild(body);
+        area.appendChild(page);
+        return { page, body };
+    }
+
+    const grid = document.createElement('div');
+    grid.className = 'grid-container';
+
+    const left = document.createElement('div');
+    left.className = 'grid-col';
+
+    const right = document.createElement('div');
+    right.className = 'grid-col';
+
+    grid.appendChild(left);
+    grid.appendChild(right);
+    page.appendChild(grid);
+    area.appendChild(page);
+
+    return { page, cols: [left, right] };
