+function wrapLatex(text) {
+    return wrapLatexPreserveBlocks(text);
+}
+
+function wrapLatexPreserveBlocks(text) {
+    if (!text) return text;
+    let s = String(text);
+
+    s = s.replace(/\^\[([^\]]+)\]/g, '^{$1}').replace(/_\[([^\]]+)\]/g, '_{$1}');
