-async function loadData(dataUrl) {
-    if (dataUrl === 'mixed') {
-        let bank = [];
-        try {
-            const raw = sessionStorage.getItem('mixedQuestions') || localStorage.getItem('mixedQuestions');
-            if (!raw) return [];
-            const tasks = JSON.parse(raw);
-            if (Array.isArray(tasks)) {
-                const seenSourceRefs = new Set();
-                for (const task of tasks) {
-                    if (!task.sourceRef || seenSourceRefs.has(task.sourceRef)) continue;
-                    seenSourceRefs.add(task.sourceRef);
-
-                    window.mainDB = { exams: [] };
-                    window.questionBank = [];
-                    try {
-                        await new Promise((resolve) => {
-                            const script = document.createElement('script');
-                            script.src = encodeURI(decodeURI(task.sourceRef));
-                            script.onload = () => { resolve(); if (script.parentNode) script.parentNode.removeChild(script); };
-                            script.onerror = () => {
-                                if (script.parentNode) script.parentNode.removeChild(script);
-                                console.warn(`Resource skip: ${task.sourceRef}`);
-                                resolve();
-                            };
-                            document.head.appendChild(script);
-                        });
-                        const loaded = (Array.isArray(window.questionBank) && window.questionBank.length > 0)
-                                       ? window.questionBank
-                                       : (window.mainDB && Array.isArray(window.mainDB.exams) ? window.mainDB.exams : []);
-                        bank = [...bank, ...loaded];
-                    } catch (e) { }
-                }
-            }
-        } catch (e) { console.error('Mixed data parse error:', e); }
-        window.mainDB = { exams: [] };
-        window.questionBank = [];
-        return bank;
-    }
-
-    window.mainDB = { exams: [] };
-    window.questionBank = [];
-    try {
-        await new Promise((resolve, reject) => {
-            const script = document.createElement('script');
-            script.src = encodeURI(decodeURI(dataUrl));
-            script.onload = () => { resolve(); if (script.parentNode) script.parentNode.removeChild(script); };
-            script.onerror = (e) => { if (script.parentNode) script.parentNode.removeChild(script); reject(e); };
-            document.head.appendChild(script);
-        });
-        return (Array.isArray(window.questionBank) && window.questionBank.length > 0)
-               ? window.questionBank
-               : (window.mainDB && Array.isArray(window.mainDB.exams) ? window.mainDB.exams : []);
-    } catch (e) { console.error('Single load error:', e); return []; }
-}
