-async function init() {
-    const params = new URLSearchParams(window.location.search);
-    const dataUrl = params.get('data');
-    const fileUrl = params.get('file');
-    AppState.data_url = dataUrl;
-    AppState.mode = params.get('mode') || 'exam';
-
-    if (dataUrl === 'mixed') {
-        try {
-            const rawMeta = sessionStorage.getItem('mixedMeta') || localStorage.getItem('mixedMeta');
-            if (rawMeta) {
-                const mixedMeta = JSON.parse(rawMeta);
-                if (mixedMeta.title) AppState.title = mixedMeta.title;
-                if (mixedMeta.qpp) AppState.qpp = parseInt(mixedMeta.qpp) || AppState.qpp;
-            }
-        } catch (e) { console.error("MixedMeta load failed:", e); }
-    }
-
-    if (params.has('title')) AppState.title = params.get('title');
-    const rawQpp = parseInt(params.get('qpp') || (dataUrl === 'mixed' ? AppState.qpp : null) || AppState.qpp);
-    AppState.qpp = Math.max(1, Math.min(8, isNaN(rawQpp) ? 2 : rawQpp));
-
-    const colsParam = parseInt(params.get('cols') || '0');
-    if (colsParam >= 2 && colsParam <= 4) {
-        AppState.cols = colsParam;
-    } else {
-        AppState.cols = AppState.qpp <= 4 ? 2 : AppState.qpp <= 6 ? 3 : 4;
-    }
-
-    const pdfContainer = document.getElementById('pdf-container');
-    if (pdfContainer) pdfContainer.style.display = 'none';
-
-    const printArea = document.getElementById('print-area');
-    if (printArea) printArea.style.display = 'flex';
-
-    const titleEl = document.getElementById('ctrl-title');
-    if (titleEl) titleEl.innerText = AppState.title;
-    updateTabs(AppState.mode);
-
-    if (AppState.mode === 'pdf' || fileUrl) {
-        if (printArea) {
-            printArea.innerHTML = '<div style="flex:1; padding:150px 0; text-align:center; color:#d32f2f; font-size:1.1em; background:#fff; font-weight:bold;">PDF 출력 기능은 현재 비활성화되어 있습니다.<br><span style="color:#666; font-weight:normal; font-size:0.9em; margin-top:10px; display:block;">JS 문항 기반의 시험지/해설지/정답표 출력을 이용해 주세요.</span></div>';
-        }
-        return;
-    }
-
-    if (dataUrl) {
-        const rawData = await loadData(dataUrl);
-
-        if (AppState.mode === 'sol') {
-            AppState.data = rawData.filter(item => item != null).map(item => ({
-                ...item,
-                answer: (item.answer !== undefined && item.answer !== null) ? String(item.answer) : '',
-                solution: item.solution || '<div class="sol-missing-msg">해설이 제공되지 않는 문항입니다.</div>'
-            }));
-        } else if (AppState.mode === 'exam') {
-            AppState.data = rawData.filter(item => item != null).map(item => ({
-                ...item,
-                content: item.content || '(문항 내용 없음)',
-                choices: Array.isArray(item.choices) ? item.choices : []
-            }));
-        } else {
-            AppState.data = rawData.filter(item => item != null);
-        }
-
-        if (dataUrl === 'mixed' && AppState.data.length === 0) {
-            if (printArea) {
-                printArea.innerHTML = '<div style="flex:1; padding:150px 0; text-align:center; color:#999; font-size:1.1em; background:#fff;">선택된 문항이 없습니다. 믹서에서 문항을 추가한 후 다시 시도해 주세요.</div>';
-            }
-            return;
-        }
-
-        if (AppState.mode === 'ans') {
-            const area = document.getElementById('print-area');
-            renderAnsGrid(area, AppState.data);
-            injectHeaderAndStyles();
-        } else {
-            await renderEngine();
-            if (!document.querySelector('#print-area .print-header')) {
-                injectHeaderAndStyles();
