-function updateTabs(mode) {
-    document.querySelectorAll('.mode-tab').forEach(btn => {
-        btn.classList.toggle('active', btn.dataset.mode === mode);
-    });
-}
-
-function switchMode(mode) {
-    if (mode === AppState.mode) return;
-    const url = new URL(window.location.href);
-    url.searchParams.set('mode', mode);
-    url.searchParams.set('qpp', AppState.qpp);
-    url.searchParams.set('cols', AppState.cols || 2);
-    window.location.href = url.toString();
-}
-
-async function renderEngine() {
-    const area = document.getElementById('print-area');
-    area.innerHTML = '';
-    pageCount = 0;
-
-    if (AppState.mode === 'ans') {
-        renderAnsGrid(area, AppState.data);
-    } else if (AppState.mode === 'sol') {
-        await renderSol(area, AppState.data);
-    } else {
-        await renderExam(area, AppState.data);
-    }
-}
-
-async function renderExam(area, bank) {
-    const numCols = AppState.cols || 2;
-    const perCol = Math.ceil(AppState.qpp / numCols);
-    const staging = document.getElementById('staging');
-    
-    const colWidthMap = { 1: '170mm', 2: '85mm', 3: '56mm', 4: '42mm' };
-    staging.style.width = colWidthMap[numCols] || '85mm';
-    
-    staging.innerHTML = '';
-
-    const boxes = bank.map((q, i) => {
-        const el = document.createElement('div');
-        el.className = 'q-box';
-        el.innerHTML = buildExamBox(q, i);
-        staging.appendChild(el);
-        return el;
-    });
-
-    if (window.MathJax?.typesetPromise) await MathJax.typesetPromise([staging]);
-    await raf();
-
-    for (let start = 0; start < boxes.length; start += AppState.qpp) {
-        const chunk = boxes.slice(start, start + AppState.qpp);
-        const page = makePage(area, 'exam');
-
-        for (let c = 0; c < numCols; c++) {
-            const colItems = chunk.slice(c * perCol, (c + 1) * perCol).map(el => el.cloneNode(true));
-            colItems.forEach(el => page.cols[c].appendChild(el));
-        }
-
-        if (window.MathJax?.typesetPromise) {
-            await MathJax.typesetPromise(page.cols);
-        }
-        await raf();
-
-        page.cols.forEach(col => fitExamColumn(col));
-
-        if (window.MathJax?.typesetPromise) {
-            await MathJax.typesetPromise(page.cols);
-        }
-        await raf();
-    }
-}
-
-function extractChoice(c) {
-    if (c === null || c === undefined) return '';
-    if (typeof c === 'object') {
-        return c.text || c.content || c.value || c.answer || Object.values(c)[0] || '';
-    }
-    return String(c);
-}
-
-function buildExamBox(q, i) {
-    const circled = ['①','②','③','④','⑤'];
-    const isMultipleChoice =
-        Array.isArray(q.choices) &&
-        q.choices.length > 0 &&
-        q.choices[0] !== "주관식" &&
-        q.choices.some(c => extractChoice(c).trim() !== "");
-
-    const choicesHTML = isMultipleChoice
-        ? `<div class="choices">${q.choices.map((c, ci) =>
-              `<div>${circled[ci] || (ci + 1) + ')'} ${wrapLatex(extractChoice(c))}</div>`).join('')}</div>`
-        : `<div class="answer-box"></div>`;
-
-    return `
-        <div class="q-num">${i + 1}.</div>
-        <div class="q-content">${wrapLatex(q.content || q.question || '')}</div>
-        ${choicesHTML}
-    `;
-}
-
-function fitExamColumn(col) {
-    const boxes = [...col.querySelectorAll('.q-box')];
-    boxes.forEach(box => fitQuestionBox(box));
-}
-
-function fitQuestionBox(box) {
-    const fitClasses = ['', 'fit-tight', 'fit-tighter', 'fit-micro'];
-
-    for (const cls of fitClasses) {
-        box.classList.remove('fit-tight', 'fit-tighter', 'fit-micro');
-        if (cls) box.classList.add(cls);
-
-        if (box.scrollHeight <= box.clientHeight + 1) {
-            return;
-        }
-    }
-
-    const choices = box.querySelector('.choices');
-    if (choices) {
-        choices.style.lineHeight = '1.2';
-        choices.style.marginTop = '1px';
-    }
-
-    const qnum = box.querySelector('.q-num');
-    if (qnum) {
-        qnum.style.marginBottom = '1px';
-    }
-}
