-function buildSolHeader(q, i) {
-    return `
-        <div class="sol-head">
-            <div class="q-num">${i + 1}.
-                <span style="font-size:9pt;font-weight:normal;">
-                    ${wrapLatex(q.content || q.question || '')}
-                </span>
-            </div>
-        </div>
-    `;
-}
-
-function buildSolFragments(q) {
-    if (q.solution_steps?.length) {
-        return q.solution_steps.map((s, si) => `
-            <div class="sol-frag">
-                <div class="sol-step"><b>[${si + 1}단계]</b> ${wrapLatexPreserveBlocks(stripCite(s))}</div>
-            </div>
-        `);
-    }
-
-    if (q.solution) {
-        const raw = stripCite(q.solution);
-
-        const hasStructuredMath =
-            /\\begin\{(array|aligned|matrix|pmatrix|bmatrix|vmatrix|Vmatrix|cases)\}/.test(raw) ||
-            /\\multicolumn|\\cline|\\hline/.test(raw);
-
-        if (hasStructuredMath) {
-            return [
-                `<div class="sol-frag"><div class="sol-step">${wrapLatexPreserveBlocks(raw)}</div></div>`
-            ];
-        }
-
-        const lines = raw
-            .split(/\n+/)
-            .map(v => v.trim())
-            .filter(Boolean);
-
-        return lines.map(line => `
-            <div class="sol-frag">
-                <div class="sol-step">${wrapLatexPreserveBlocks(line)}</div>
-            </div>
-        `);
-    }
-
-    return [
-        `<div class="sol-frag"><div class="sol-step" style="color:#94a3b8;font-size:8pt;">해설 없음</div></div>`
-    ];
-}
-
-async function renderSol(area, bank) {
-    let p = makePage(area, 'sol');
-    let colIdx = 0;
-
-    async function ensureFitOrAdvance(targetCol, node) {
-        targetCol.appendChild(node);
-
-        if (window.MathJax?.typesetPromise) {
-            await MathJax.typesetPromise([targetCol]);
-        }
-        await raf();
-
-        const overflowed = targetCol.scrollHeight > targetCol.clientHeight + 1;
-
-        if (!overflowed) return true;
-
-        node.remove();
-
-        if (colIdx === 0) {
-            colIdx = 1;
-        } else {
-            p = makePage(area, 'sol');
-            colIdx = 0;
-        }
-        return false;
-    }
-
-    for (let i = 0; i < bank.length; i++) {
-        const q = bank[i];
-
-        const headWrap = document.createElement('div');
-        headWrap.innerHTML = buildSolHeader(q, i).trim();
-        const headEl = headWrap.firstElementChild;
-
-        let placedHeader = false;
-        while (!placedHeader) {
-            const targetCol = p.cols[colIdx];
-            placedHeader = await ensureFitOrAdvance(targetCol, headEl.cloneNode(true));
-        }
-
-        const fragments = buildSolFragments(q);
-
-        for (const fragHTML of fragments) {
-            const fragWrap = document.createElement('div');
-            fragWrap.innerHTML = fragHTML.trim();
-            const fragEl = fragWrap.firstElementChild;
-
-            let placedFrag = false;
-            while (!placedFrag) {
-                const targetCol = p.cols[colIdx];
-                placedFrag = await ensureFitOrAdvance(targetCol, fragEl.cloneNode(true));
-            }
-        }
-
-        const divider = document.createElement('div');
-        divider.className = 'sol-divider';
-
-        let placedDivider = false;
-        while (!placedDivider) {
-            const targetCol = p.cols[colIdx];
-            placedDivider = await ensureFitOrAdvance(targetCol, divider.cloneNode(true));
-        }
-    }
-}
-
-function renderAnsGrid(area, bank) {
-    const p = makePage(area, 'ans');
-    const grid = document.createElement('div');
-    grid.className = 'ans-grid';
-
-    const half = Math.ceil(bank.length / 2);
-
-    for (let i = 0; i < half; i++) {
-        const leftCell = document.createElement('div');
-        leftCell.className = 'ans-cell';
-        const leftAns = bank[i] ? wrapLatex(String(bank[i].answer ?? '–')) : '';
-        leftCell.innerHTML = `<b style="font-size:10.5pt;min-width:28px;">${i + 1}.</b><span style="font-size:10.5pt;">${leftAns}</span>`;
-        grid.appendChild(leftCell);
-
-        const rightCell = document.createElement('div');
-        rightCell.className = 'ans-cell';
-        const rIdx = half + i;
-        const rightAns = bank[rIdx] ? wrapLatex(String(bank[rIdx].answer ?? '–')) : '';
-        rightCell.innerHTML = bank[rIdx]
-            ? `<b style="font-size:10.5pt;min-width:28px;">${rIdx + 1}.</b><span style="font-size:10.5pt;">${rightAns}</span>`
-            : '';
-        grid.appendChild(rightCell);
-    }
-
-    p.body.appendChild(grid);
-    if (window.MathJax?.typesetPromise) MathJax.typesetPromise([p.body]);
